/** @typedef {import('./data').BoardInitOption} BoardInitOption */
/** @typedef {import('./data').PlayerInfo} PlayerInfo */
import {canvasFont} from "./canvasFontLoader.js";
import {canvasImage} from "./canvasImageLoader.js";
import {downloadImage} from "./downloadImage.js";
import {mouseControl} from "./mouseControl.js";
import {PlayerControl} from "./playerControl.js";
import {Stand} from "./stand.js";
import {Panel} from "./panel.js";
import {Piece} from "./piece.js";
import {EnPassant} from "./enPassant.js";
import {Bod} from "./bod.js";
import {boards, games} from "./data.js";
import {CpuEngine} from "./cpu.js";

/** зЫ§гБЃзЃ°зРЖгВѓгГ©гВє */
export class Board{
	/** @typedef {Object} Board */
	#mouseControl
	#playerControl
	#option
	#beforeTurn

	/**
	 * @typedef {Object} Record - е±АйЭҐгБЃи®ШйМ≤
	 * @prop {Object} from
	 * @prop {number} from.pX - зІїеЛХеЕГгБЃеИЧ
	 * @prop {number} from.pY - зІїеЛХеЕГгБЃи°М
	 * @prop {Object} to
	 * @prop {number} to.pX - зІїеЛХеЕИгБЃеИЧ
	 * @prop {number} to.pY - зІїеЛХеЕИгБЃи°М
	 * @prop {number} deg - йІТгБЃиІТеЇ¶
	 * @prop {string} pieceChar - йІТгБЃдЄАжЦЗе≠Чи°®и®Ш
	 * @prop {string} end - ж£Ли≠Ьи°®з§ЇгБЃжЬЂе∞ЊгБЂи®ШиЉЙгБЩгВЛжЦЗе≠Ч
	 * @prop {string} fieldText - йІТйЕНзљЃгБЃгГЖгВ≠гВєгГИ
	 * @prop {number[][]} fieldMoved - йІТгБЃзІїеЛХжЄИгБњеИ§еЃЪ
	 * @prop {string|null} comment - ж£Ли≠ЬгВ≥гГ°гГ≥гГИ
	 */

	/** гВ≤гГЉгГ†гВТеЃЯи°МгБЩгВЛ
	 * @param {HTMLCanvasElement}} canvas - Canvasи¶Бзі†
	 * @param {BoardInitOption} option - гГЬгГЉгГЙгБЃеИЭжЬЯеМЦгВ™гГЧгВЈгГІгГ≥
	 * @returns {Board}
	 */
	static run(canvas, option){
		return new Board(canvas, option);
	}

	/**
	 * @param {HTMLCanvasElement} canvas - Canvasи¶Бзі†
	 * @param {BoardInitOption} option - гГЬгГЉгГЙгБЃеИЭжЬЯеМЦгВ™гГЧгВЈгГІгГ≥
	 */
	constructor(canvas, option){
		const {
			name,
			variant,
			url,
			desc,
			playBoard,
			playerOptions=[],
			players=playerOptions.some(({gameName}, i)=>1 < i && gameName)? 4: 2,
			useStand=false,
			canvasWidth=undefined,
			canvasHeight=undefined,
			canvasFit="overflow",
			boardLeft=5,
			boardTop=5,
			panelWidth=50,
			panelHeight=0|panelWidth*1.1,
			pieceSize=0|panelWidth*0.9,
			useRankSize = true,
			isDrawShadow = true,
			borderWidth=Math.min(panelWidth, panelHeight)/30,
			backgroundColor="#00000000",
			isHeadless=false,
			autoDrawing=!isHeadless,
			moveMode="normal",
			usePlayerControl=!isHeadless,
			onDrawed=e=>{},
			onTurnEnd=(e,turn)=>{},
			onGameOver=(e,i)=>alert(`гГЧгГђгВ§гГ§гГЉ${i+1}гБЃжХЧеМЧгБІгБЩгАВ`)
		} = option;

		this.#option = option;
		this.isHeadless = isHeadless;
		this.name = name;
		this.variant = variant;
		this.url = url;
		this.desc = desc;

		// еИЭжЬЯеМЦ
		this.ctx = null;
		this.canvas = null;
		let canvasFontAsync = null;
		let canvasImageAsync = null;
		if(!isHeadless){
			canvasFontAsync = canvasFont.importAsync();
			canvasImageAsync = canvasImage.importAsync();
			this.canvas = canvas;
			this.ctx = canvas.getContext("2d");
			this.ctx.clearRect(0, 0, canvas.width, canvas.height);
		}

		this.pieces = Piece.getPieces(this.ctx, {
			size: pieceSize,
			useRankSize,
			isDrawShadow
		});

		// гГЬгГЉгГЙжГЕе†±
		if(!boards[playBoard]) throw Error(`playBoard=${playBoard}, Unknown board name.`);
		Object.assign(this, boards[playBoard]);
		if(![2, 4].includes(players)) throw Error(`players=${players}, players need 2 or 4.`);
		this.playerLen = players;
		this.left = boardLeft;
		this.top = boardTop;
		this.panelWidth = panelWidth;
		this.panelHeight = panelHeight;
		this.borderWidth = borderWidth;
		this.pieceSize = pieceSize;
		this.canvasBackgroundColor = backgroundColor;

		// гГЮгВєзЫЃгГЗгГЉгВњгВТжІЛзѓЙ
		this.field = this.field.map((row, pY)=>
			[...row].map((char, pX)=>{
				const center = boardLeft+panelWidth*(pX+1);
				const middle = boardTop+panelHeight*(pY+1)
				return new Panel(this.ctx, char, center, middle, panelWidth, panelHeight, pX, pY, borderWidth);
			})
		);
		this.xLen = this.field[0].length;
		this.yLen = this.field.length;

		// гГЧгГђгВ§гГ§гГЉи®≠еЃЪ
		this.players = new Map();
		for(let id=0;id<players;id++){
			const deg = this.degNormal(id)
			const status = {
				...playerOptions[id],
				id,
				deg,
				degChar: Piece.degChars[deg],
				alive: true,
			};
			// CPUгВ®гГ≥гВЄгГ≥гБЃеИЭжЬЯеМЦ
			status.cpu = new CpuEngine(this, status),
			this.players.set(deg, status);
			// йІТгБЃеИЭжЬЯйЕНзљЃ
			if(!status.gameName) continue;
			try{
				this.putStartPieces(id, status.gameName, status.pieceSet);
			}
			catch(ex){
				console.error(ex);
			}
		}

		// жППеЖЩеѓЄж≥ХгВТи®≠еЃЪ
		this.width = this.panelWidth*(this.xLen+1);
		this.height = this.panelHeight*(this.yLen+1);
		this.right = boardLeft+this.width;
		this.bottom = boardTop+this.height;
		this.stand = new Stand(this);
		if(!isHeadless){
			canvas.width = canvasWidth ?? (useStand? this.stand.right: this.right)+5;
			canvas.height = canvasHeight ?? this.bottom+5;

			// гВ≠гГ£гГ≥гГРгВєгВµгВ§гВЇиЗ™еЛХи™њжХі
			const {style} = canvas;
			if(canvasFit === "overflow"){
				if(style.maxWidth === "") style.maxWidth = "97vw";
				if(style.maxHeight === "") style.maxHeight = "92vh";
			}
			else if(canvasFit === "horizontal"){
				if(style.width === "") style.width = "97vw";
			}
			else if(canvasFit === "vertical"){
				if(style.height === "") style.height = "92vh";
			}
			else if(canvasFit === "parentOverflow"){
				if(style.maxWidth === "") style.maxWidth = "100%";
				if(style.maxHeight === "") style.maxHeight = "100%";
			}
			else if(canvasFit === "parentHorizontal"){
				if(style.width === "") style.width = "100%";
			}
			else if(canvasFit === "parentVertical"){
				if(style.height === "") style.height = "100%";
			}
		}

		// иЗ™еЛХжППеЖЩжЫіжЦ∞и®≠еЃЪ
		this.autoDrawing = autoDrawing;
		if(autoDrawing){
			canvasFontAsync.then(()=>this.draw());
			canvasImageAsync.then(()=>this.draw());
			this.draw();
		}

		this.onDrawed = onDrawed;
		this.onTurnEnd = onTurnEnd;
		this.onGameOver = onGameOver;
		this.moveMode = moveMode;

		/** гВ≤гГЉгГ†гБЃи®ШйМ≤
		 * @type {Record[]}
		 */
		this.record = [];
		/** гВ≤гГЉгГ†гБЃгВњгГЉгГ≥
		 * @type {number}
		 */
		this.turn = 0;
		if(!isHeadless) this.#mouseControl = mouseControl(this);
		if(usePlayerControl){
			this.#playerControl = this.makePlayerControl();
			this.#playerControl.add();
		}
		this.enPassant = new EnPassant();
	}

	/** жУНдљЬгГСгГНгГЂгВТжІЛзѓЙ
	 * @param {string[]} compList - и°®з§ЇгБЩгВЛгВ≥гГ≥гГИгГ≠гГЉгГЂгБЃдЄАи¶І
	 * @returns {PlayerControl}
	 */
	makePlayerControl(compList){
		this.#playerControl = new PlayerControl(this, compList);
		return this.#playerControl;
	}

	/** гГЬгГЉгГЙгВТйЦЙгБШгВЛ */
	close(){
		this.#mouseControl?.removeEvent();
		this.#playerControl?.remove();
	}

	/** зПЊеЬ®гБЃжЙЛзХ™гБЃгГЧгГђгВ§гГ§гГЉжГЕе†±гВТеПЦеЊЧ
	 * @returns {Object<string, any>|"PlayerInfo"} - зПЊеЬ®гБЃгГЧгГђгВ§гГ§гГЉжГЕе†±
	 */
	getActivePlayer(){
		return [...this.players.values()][this.turn%this.playerLen];
	}

	/** иІТеЇ¶гВТж≠£и¶ПеМЦ
	 * @param {number} playeaIdOrDeg - гГЧгГђгВ§гГ§гГЉзХ™еПЈгБЊгБЯгБѓиІТеЇ¶
	 * @returns {number}
	 */
	degNormal(playeaIdOrDeg){
		let deg = playeaIdOrDeg;
		if(0 < deg && deg < 4) deg = 0|deg*360/this.playerLen;
		do{deg = (deg+360)%360} while(deg<0);
		return deg;
	}

	/** зЫ§йЭҐгВТеЫЮиїҐ
	 * @param {boolean} isRight - еЫЮиїҐжЦєеРС
	 */
	rotate(isRight=true){
		let deg = this.degNormal(1);
		if(!isRight) deg = -deg;
		this.#rotateField(deg);
		this.stand.rotate(deg);
		if(this.autoDrawing) this.draw();
	}

	/** йІТйЕНзљЃгВТеЫЮиїҐ
	 * @param {number} deg - еЫЮиїҐиІТ (90гБЃеАНжХ∞)
	 */
	#rotateField(deg){
		const {field, xLen, yLen} = this;

		deg = this.degNormal(deg);
		if(deg === 0) return;
		if(![90, 180, 270].includes(deg)) throw Error(`deg=${deg}, deg need multiple of 90.`);

		let fieldPieces = field.map(row=>row.map(({piece})=>piece));
		if([90, 270].includes(deg)){
			// 2жђ°йЕНеИЧгВТиїҐзљЃ
			const transpose = a => a[0].map((_, c) => a.map(r => r[c]));
			if(xLen !== yLen) throw Error(`cols=${xLen} != rows=${yLen}, Not rows = cols.`);
			fieldPieces = transpose(fieldPieces);
		}
		if([180, 270].includes(deg)){
			fieldPieces.reverse();
		}
		fieldPieces.forEach(row=>{
			row.forEach(piece=>{
				if(!piece) return;
				piece.deg += deg;
			});
			if([90, 180].includes(deg)) row.reverse();
		});
		field.forEach((row, pY)=>
			row.forEach((panel, pX)=>
				panel.piece = fieldPieces[pY][pX]
			)
		);
	}

	/** йІТгБЃеИЭжЬЯйЕНзљЃ
	 * @param {number} playerId - гГЧгГђгВ§гГ§гГЉзХ™еПЈ
	 * @param {string} gameName - гВ≤гГЉгГ†еРН(еЯЇжЇЦгБ®гБ™гВЛйІТгБЃйЕНзљЃгВїгГГгГИ)
	 * @param {string} pieceSet - йІТгБЃйЕНзљЃгГСгВњгГЉгГ≥
	 */
	putStartPieces(playerId, gameName, pieceSet="default"){
		const {pieces} = this;

		const deg = this.degNormal(playerId);
		this.#rotateField(deg);
		const pos = games[gameName].position[this.xLen][pieceSet];
		if(!pos) throw Error(`games["${gameName}"].position["${this.xLen}"]["${pieceSet}"]is null.`);
		pos.forEach((row, i)=>{
			if(row.length < this.xLen) throw Error(row.join(""));
			const pY = i+this.yLen - pos.length;
			[...row].forEach((char, pX)=>{
				if(!pieces[char]) return;
				this.field[pY][pX].piece = pieces[char].clone();
			});
		});
		this.#rotateField(-deg);
		if(this.autoDrawing) this.draw();
	}

	/** йІТгБЃйЕНзљЃ
	 * @param {string} piece - йІТгБЃи°®зПЊжЦЗе≠Ч
	 * @param {number} pX - XжЦєеРСйЕНзљЃдљНзљЃ(гГЮгВєзЫЃеЯЇжЇЦ)
	 * @param {number} pY - YжЦєеРСйЕНзљЃдљНзљЃ(гГЮгВєзЫЃеЯЇжЇЦ)
	 * @param {number} playeaIdOrDeg - гГЧгГђгВ§гГ§гГЉзХ™еПЈгБЊгБЯгБѓйІТгБЃйЕНзљЃиІТ
	 * @param {Object} option - гВ™гГЧгВЈгГІгГ≥
	 * @param {number} option.displayPtn - и°®з§ЇжЦЗе≠ЧеИЧгВТе§ЙжЫі(1гАЬ)
	 * @param {boolean} option.isMoved - еИЭеЫЮзІїеЛХжЄИгБњгБЛеР¶гБЛ
	 */
	putNewPiece(piece, pX, pY, playeaIdOrDeg, option={}){
		const {displayPtn=0, isMoved=false} = option;
		const {pieces} = this;

		const deg = this.degNormal(playeaIdOrDeg);
		if(typeof piece === "string"){
			piece = new Piece(this.ctx, pieces[piece], {displayPtn, deg, isMoved});
		}
		this.field[pY][pX].piece = piece;
		if(this.autoDrawing) this.draw();
	}

	/** жЦЗе≠ЧеИЧгБЛгВЙйІТгВТйЕНзљЃ
	 * {string} text - йІТйЕНзљЃгВТи°®гБЩжЦЗе≠ЧеИЧ
	 */
	setTextPieces(text){
		const {field, pieces, xLen, yLen} = this;

		const standTitle = "жМБйІТпЉЪ";
		// BODељҐеЉП
		if(0<text.indexOf(standTitle)) text = Bod.convTextPieces(text);

		// жОТйЩ§гБЩгВЛи®ШеПЈ
		const noises = "вФПвФБвФѓвФУвФЧвФЈвФЫвФГвФВвФ†вФАвФЉвФ®вАХ";

		// йЕНеИЧе§ЙжПЫ
		const texts = [text].concat(
				[...noises],
				Object.values(Piece.degChars).map(c=>"\n"+c+standTitle)
			).reduce(
				(text,char)=>
					text.replace(new RegExp(char,"g"), "")
			).replace(/\n\n/g, "\n")
			.replace(/гАА/g, "гГї")
			.trim()
			.split(/\n/)
			.map(
				row=>row.match(/.{2}/g));

		// гГЬгГЉгГЙгБЂйІТгВТйЕНзљЃ
		for(let pY=0;pY<yLen;pY++){
			for(let pX=0;pX<xLen;pX++){
				try{
					const text = texts[pY][pX];
					field[pY][pX].piece = Piece.stringToPiece(pieces, text);
				}
				catch(ex){
					field[pY][pX].piece = null;
				}
			}
		}

		// йІТеП∞гБЃи™≠гБњиЊЉгБњгВТеЊЕж©Я
		while(!this.stand){}
		// жМБгБ°йІТгВТйЕНзљЃ
		this.stand.clear();
		const standTexts = texts[yLen];
		if(standTexts){
			standTexts.forEach(text=>{
				const piece = Piece.stringToPiece(pieces, text);
				if(!piece) return;
				this.stand.add(piece);
			});
		}
		if(this.autoDrawing) this.draw();
	}

	/** иІТеЇ¶еЯЇжЇЦгБЃгГЮгВєзЫЃгБЃи°МгВТеПЦеЊЧгБЩгВЛ
	 * @param {number} pX - гГЮгВєзЫЃгБЃеИЧ
	 * @param {number} pY - гГЮгВєзЫЃгБЃи°М
	 * @param {number} deg - иІТеЇ¶
	 * @param {number} offsetDeg - и£Ьж≠£иІТеЇ¶
	 * @returns {number}
	 */
	getRow(pX, pY, deg, offsetDeg=0){
		const {xLen, yLen} = this;

		deg = this.degNormal(deg+offsetDeg);
		return (
			deg === 0? yLen-1-pY:
			deg === 90? pX:
			deg === 180? pY:
			deg === 270? xLen-1-pX:
			-1
		);
	}

	/** иІТеЇ¶еЯЇжЇЦгБЃгГЮгВєзЫЃгБЃеИЧгВТеПЦеЊЧгБЩгВЛ
	 * @param {number} pX - гГЮгВєзЫЃгБЃеИЧ
	 * @param {number} pY - гГЮгВєзЫЃгБЃи°М
	 * @param {number} deg - иІТеЇ¶
	 * @param {number} offsetDeg - и£Ьж≠£иІТеЇ¶
	 * @returns {number}
	 */
	getCol(pX, pY, deg, offsetDeg=0){
		const {xLen, yLen} = this;

		deg = this.degNormal(deg+offsetDeg);
		return (
			deg === 0? pX:
			deg === 90? yLen-1-pY:
			deg === 180? xLen-1-pX:
			deg === 270? pY:
			-1
		);
	}

	/** гГЧгГ≠гГҐгГЉгВЈгГІгГ≥гВ®гГ™гВҐеЖЕгБІгБВгВЛгБЛеИ§еИ•
	 * @param {Panel} panel - гГЮгВєзЫЃ
	 * @returns {{ 
	 * 		canPromo: boolean,
	 * 		forcePromo: boolean
	 * }}
	 */
	checkCanPromo(panel){
		const {yLen} = this;
		const {piece, pX, pY} = panel;
		const {deg} = piece;

		const [promoLine, forcePromoLine] = [
			piece.game.promoLine,
			piece.forcePromoLine
		].map(line=>yLen-line-(0|this.promoLineOffset));

		let row;
		if(!this.sidePromo){
			row = this.getRow(pX, pY, deg);
		}
		else{
			row = Math.max(
				...Object.keys(Piece.degChars)
				.map(d=>0|d)
				.filter(d=>d!==deg)
				.map(
					d=>this.getRow(pX, pY, d, 180)
				)
			);
		}
		return {
			canPromo: promoLine <= row,
			forcePromo: forcePromoLine <= row
		};
	}

	/** жХЧеМЧгБЧгБЯгГЧгГђгВ§гГ§гГЉгБМе≠ШеЬ®гБЩгВЛгБЛзҐЇи™НгБЧгАБгВ§гГЩгГ≥гГИгВТзЩЇзФЯгБХгБЫгВЛ */
	#emitGameOver(){
		this.players.forEach((player, deg)=>{
			if(!player.alive) return;
			if(this.field.flat().some(
				({piece})=>
					piece?.deg === deg
					&& piece.hasAttr("king")
				)
			) return;
			player.alive = false;
			this.onGameOver?.(this, player.id);
		});
	}

	/** гГЧгГ≠гГҐгГЉгВЈгГІгГ≥еЗ¶зРЖ
	 * @param {Panel} fromPanel - зІїеЛХеЕГгБЃгГЮгВєзЫЃ
	 * @param {Panel} toPanel - йБЄжКЮдЄ≠гБЃгГЮгВєзЫЃ
	 * @param {boolean} canPromo - жИРгВЛгБУгБ®гБМгБІгБНгВЛ
	 * @param {boolean} forcePromo - жИРгВКгВТеЉЈеИґгБЩгВЛ
	 * @param {boolean} isCpuMove - CPUгБЂгВИгВЛзІїеЛХгБЛ
	 */
	#promoDialog(fromPanel, toPanel, canPromo, forcePromo, isCpuMove=false){
		const {moveMode} = this;
		const {piece} = toPanel;

		// гГЧгГ≠гГҐгГЉгВЈгГІгГ≥еЗ¶зРЖ
		if(!piece.promo || piece.hasAttr("promoted") || piece.hasAttr("cantPromotion") || !canPromo){
			this.addRecord({fromPanel, toPanel});
			return;
		}

		if(this.isHeadless || isCpuMove){
			if(canPromo){
				const promoChar = Object.keys(piece.promo)[0];
				piece.promotion(promoChar);
				this.addRecord({fromPanel, toPanel, end:"жИР"});
				return;
			}
			else{
				this.addRecord({fromPanel, toPanel});
				return;
			}
		}

		do{
			for(const [char, {name}] of Object.entries(piece.promo)){
				if(confirm(`жИРгВКгБЊгБЩгБЛ?
${piece.char}:${piece.name}
гААвЖУ
${char}:${name}`)){
					piece.promotion(char);
					this.addRecord({fromPanel, toPanel, end:"жИР"});
					return;
				}
			}
		} while(moveMode !== "free" && forcePromo);
		this.addRecord({fromPanel, toPanel, end:"дЄНжИР"});
	}

	/** йІТгВТзІїеЛХ
	 * @param {Panel} fromPanel - зІїеЛХеЕГгБЃгГЮгВєзЫЃ
	 * @param {Panel} toPanel - йБЄжКЮдЄ≠гБЃгГЮгВєзЫЃ
	 * @param {boolean} isCpuMove - CPUгБЂгВИгВЛзІїеЛХгБЛ
	 */
	movePiece(fromPanel, toPanel, isCpuMove=false){
		const {stand, moveMode, enPassant} = this;

		if(!fromPanel
			|| moveMode === "viewOnly"
			|| toPanel.hasAttr("keepOut")
			|| toPanel.piece === fromPanel.piece
			|| toPanel.piece?.deg === fromPanel.piece.deg
			|| moveMode !== "free" && !toPanel.isTarget
			|| !isCpuMove && this.getActivePlayer().cpuEngine
		) return;

		let {canPromo, forcePromo} = this.checkCanPromo(fromPanel);

		stand.capturePiece(
			fromPanel.piece,
			toPanel.piece,
			toPanel.hasAttr("capture"),
			toPanel.hasAttr("cantCapture")
		);

		toPanel.piece = fromPanel.piece;
		toPanel.piece.isMoved = true;
		fromPanel.piece = null;

		const afterPromo = this.checkCanPromo(toPanel);
		canPromo ||= afterPromo.canPromo;
		forcePromo ||= afterPromo.forcePromo;

		// гВҐгГ≥гГСгГГгВµгГ≥
		enPassant.setMoved(toPanel);

		// гГЧгГ≠гГҐгГЉгВЈгГІгГ≥еЗ¶зРЖ
		this.#promoDialog(fromPanel, toPanel, canPromo, forcePromo, isCpuMove);

		// гГЧгГђгВ§гГ§гГЉгБЃгВ≤гГЉгГ†гВ™гГЉгГРгГЉеИ§еЃЪ
		this.#emitGameOver();
	}

	/** ж£Ли≠ЬгВТињљи®Ш
	 * @param {Panel} toPanel - зІїеЛХеЕИгБЃгГЮгВєзЫЃ
	 * @param {Object} option - гВ™гГЧгВЈгГІгГ≥
	 * @param {Panel} option.fromPanel - зІїеЛХеЕГгБЃгГЮгВєзЫЃ
	 * @param {string} option.end - гВ™гГЧгВЈгГІгГ≥=жИР|дЄНжИР|жЙУ
	 */
	addRecord(option={}){
		if(this.isHeadless) return;
		const {record} = this;
		const {fromPanel={}, toPanel={}, end="", inc=1} = option;
		const {piece={}} = toPanel;

		this.turn += inc;
		record[this.turn] = {
			from: {
				pX: fromPanel.pX,
				pY: fromPanel.pY
			},
			to: {
				pX: toPanel.pX,
				pY: toPanel.pY,
			},
			deg: piece.deg,
			pieceChar: piece.char,
			end,
			fieldText: this.getTextPieces("compact", true),
			fieldMoved: this.field.map(row=>
				row.map(({piece})=>
					piece?.isMoved? 1: 0
				)
			)
		};
		if(0 < inc) record.splice(this.turn+1);
		// гВњгГЉгГ≥гБМе§ЙгВПгБ£гБЯ
		if(this.#beforeTurn !== this.turn){
			this.#beforeTurn = this.turn;
			// гВњгГЉгГ≥гВ®гГ≥гГЙгВ§гГЩгГ≥гГИ
			this.onTurnEnd?.(this, this.turn);
			// CPUгБЃгВњгГЉгГ≥гВТйА≤гВБгВЛ
			this.getActivePlayer().cpu.playTurn();
		}

	}

	/** ж£Ли≠ЬгВ≥гГ°гГ≥гГИгВТињљи®Ш
	 * @param {string} comment - ж£Ли≠ЬгВ≥гГ°гГ≥гГИ
	 * @param {number} shiftTurn - гБЪгВЙгБЩжЙЛжХ∞
	 */
	addRecordComment(comment, shiftTurn=0){
		this.record[this.turn+shiftTurn].comment = comment;
	}

	/** и®ШйМ≤гБЃеПВзЕІжЙЛжХ∞гВТеИЗгВКжЫњгБИгВЛ
	 * @param {number} inc - еИЗгВКжЫњгБИгБЯгБДжЙЛжХ∞гБЃеЈЃеИЖ
	 */
	#switchRecord(inc){
		const {record} = this;
		if(!record[this.turn+inc]) return;

		this.turn += inc;
		const {fieldText, fieldMoved} = record[this.turn];
		this.setTextPieces(fieldText);
		this.field.forEach((row, pY)=>
			row.forEach(({piece}, pX)=>{
				if(!piece) return;
				piece.isMoved = !!fieldMoved[pY][pX];
			})
		);
	}

	/** и®ШйМ≤гБЃжЙЛгВТжИїгБЩ */
	undoRecord(){
		this.#switchRecord(-1);
	}

	/** и®ШйМ≤гБЃжЙЛгВТйА≤гВБгВЛ */
	redoRecord(){
		this.#switchRecord(1);
	}

	/** и®ШйМ≤гБЃжЙЛгВТзІїеЛХ
	 * @param {number} turn - жЙЛжХ∞
	 */
	moveRecord(turn){
		this.turn = turn;
		this.#switchRecord(0);
	}

	/** е±АйЭҐгБЃи®ШйМ≤гВТжЦЗе≠ЧеИЧгБЂе§ЙжПЫ
	 * @param {Record} record - е±АйЭҐгБЃи®ШйМ≤
	 * @param {number} turn - жЙЛжХ∞
	 * @param {boolean} isNumOnly - еЇІж®ЩгВТжХ∞е≠ЧгБІи°®зПЊ
	 * @returns {string}
	 */
	record2String(record, turn, isNumOnly=false){
		const {to, from, deg, pieceChar, end} = record;
		if(turn === 0) return "0: йЦЛеІЛе±АйЭҐ";

		const getPX = ({pX})=> (this.xLen-pX).toString(isNumOnly? 10: 36);
		const getPY = ({pY})=> (pY+1).toString(isNumOnly? 10: 36);
		const numSep = isNumOnly? ",": "";
		return `${ 
			turn}: ${ 
			Piece.degChars[deg]}${ 
			getPX(to)}${ 
			numSep}${ 
			getPY(to)}${ 
			pieceChar}${ 
			end}${ 
			from.pX === undefined? "": ` (${ 
				getPX(from)}${ 
				numSep}${ 
				getPY(from)
			})`}`;
	}

	/** и°®з§ЇзФ®гБЃж£Ли≠ЬгВТеПЦеЊЧ
	 * @param {boolean} isNumOnly - еЇІж®ЩгВТжХ∞е≠ЧгБІи°®зПЊ
	 * @returns {string}
	 */
	getTextRecord(isNumOnly=false){
		return this.record.slice(0, this.turn+1).map((record, i)=>
			this.record2String(record, i, isNumOnly)
		).join("\n");
	}

	/** ж£Ли≠ЬгГЗгГЉгВњгВТеПЦеЊЧ
	 * @param {boolean} isEncode - гВ®гГ≥гВ≥гГЉгГЙжЬЙзД°
	 * @returns {string}
	 */
	getJsonRecord(isEncode=true){
		const jsonRecord = JSON.stringify(this.record, null, "");
		return isEncode? encodeURI(jsonRecord): jsonRecord;
	}

	/** ж£Ли≠ЬгГЗгГЉгВњгВТеЕ•еКЫ
	 * @param {string} record - ж£Ли≠ЬгГЗгГЉгВњ
	 * @param {number} turn - жЙЛжХ∞
	 */
	setJsonRecord(record, turn){
		this.record = JSON.parse(decodeURI(record));
		this.moveRecord(turn ?? this.record.length-1);
	}

	/** зЫ§гВТжППеЖЩ */
	draw(){
		if(this.isHeadless) return;
		const {ctx, canvas, left, top, width, height, panelWidth, panelHeight} = this;

		//жЬАеИЭгБЃи®ШйМ≤
		if(this.turn === 0) this.addRecord({inc: 0});

		// жППеЖЩгВТеИЭжЬЯеМЦ
		ctx.restore();
		ctx.save();
		ctx.clearRect(0, 0, canvas.width, canvas.height);
		ctx.fillStyle = this.canvasBackgroundColor;
		ctx.fillRect(0, 0, canvas.width, canvas.height);

		// е§ЦжЮ†гВТжППеЖЩ
		ctx.fillStyle = this.backgroundColor;
		ctx.lineWidth = this.borderWidth;
		ctx.strokeStyle = this.borderColor;

		ctx.save();
		ctx.translate(left, top);
		ctx.fillRect(0, 0, width, height);
		ctx.strokeRect(0, 0, width, height);
		ctx.translate(panelWidth/2, panelHeight/2);
		ctx.strokeRect(0, 0, width-panelWidth, height-panelHeight);
		ctx.restore();
		this.stand.draw();

		// гГЮгВєзЫЃгВТжППеЖЩ
		this.field.forEach(row=>{
			row.forEach(panel=>{
				panel.draw();
			});
		});
		if(this.onDrawed) this.onDrawed(this);
	}

	/** йІТйЕНзљЃгВТгГЖгВ≠гВєгГИгБІеПЦеЊЧ
	 * @param {"default"|"compact"|"bod"} mode - гГЖгВ≠гВєгГИељҐеЉП
	 * @param {boolean} isAlias - гВ®гВ§гГ™гВҐгВєи°®з§Ї
	 * @returns {string}
	 */
	getTextPieces(mode="default", isAlias=false){
		return mode === "bod"?
			Bod.getTextPieces(this):
			this.toString(mode === "compact", isAlias);
	}

	/** ж£Ли≠ЬгВ≥гГ°гГ≥гГИгВТеПЦеЊЧ
	 * @param {number} shiftTurn - гБЪгВЙгБЩжЙЛжХ∞
	 * @returns {string}
	 */
	getRecordComment(shiftTurn=0){
		return this.record[this.turn+shiftTurn] ?? "";
	}

	/** йІТйЕНзљЃгВТгГЖгВ≠гВєгГИгБІеПЦеЊЧ
	 * @param {boolean} isCompact - гВ≥гГ≥гГСгВѓгГИи°®з§Ї
	 * @param {boolean} isAlias - гВ®гВ§гГ™гВҐгВєи°®з§Ї
	 */
	toString(isCompact=false, isAlias=false){
		const {xLen} = this;

		let header = "";
		let footer = "";
		let panelOuter = "";
		let panelSep = "";
		let rowSep = "\n";

		if(!isCompact){
			header = `вФП${Array(xLen).fill("вФБвФБ").join("вФѓ")}вФУ\n`;
			footer = `\nвФЧ${Array(xLen).fill("вФБвФБ").join("вФЈ")}вФЫ`;
			panelOuter = "вФГ";
			panelSep = "вФВ";
			rowSep = `\nвФ†${Array(xLen).fill("вФАвФА").join("вФЉ")}вФ®\n`;
		}

		return (
			header+
			this.field.map(row=>
				panelOuter+
				row.map(panel=>
					panel.piece?.toString(isAlias) ?? panel.toString(isCompact)
				).join(panelSep)+
				panelOuter
			).join(rowSep)+
			footer+
			this.stand.toString(isCompact)
		);
	}

	/** зФїеГПгВТеПЦеЊЧ
	 * @param {string} fileName - гГХгВ°гВ§гГЂеРН
	 * @param {string} ext - жЛ°еЉµе≠Р
	 * @returns {Promise<void>}
	 */
	async downloadImage(fileName, ext, urlType){
		await downloadImage(this.canvas, fileName ?? this.name ?? "shogicross", ext, urlType);
	}

	/** зЫ§йЭҐгВТгВѓгГ≠гГЉгГ≥
	 * @returns {Board}
	 */
	clone(){
		// гВѓгГ≠гГЉгГ≥зФ®гБЃжЦ∞гБЧгБДгВ™гГЧгВЈгГІгГ≥гВ™гГЦгВЄгВІгВѓгГИгВТдљЬжИР
		const cloneOption = {...this.#option, isHeadless: true};

		// дњЃж≠£гБЧгБЯгВ™гГЧгВЈгГІгГ≥гБІжЦ∞гБЧгБДBoardгВ§гГ≥гВєгВњгГ≥гВєгВТдљЬжИР
		const newBoard = new Board(null, cloneOption);

		// зЫ§дЄКгБЃйІТгВТгВ≥гГФгГЉ
		for(let y=0;y<this.yLen;y++){
			for(let x=0;x<this.xLen;x++){
				const originalPanel = this.field[y][x];
				const newPanel = newBoard.field[y][x]; // жЧҐгБЂPanelгВ™гГЦгВЄгВІгВѓгГИгБѓзФЯжИРгБХгВМгБ¶гБДгВЛ
				if(originalPanel.piece){
					newPanel.piece = originalPanel.piece.clone();
				}
				else{
					newPanel.piece = null;
				}
			}
		}

		// жМБгБ°йІТгВТгВ≥гГФгГЉ
		newBoard.stand.clear(); // гБЊгБЪгВѓгГ™гВҐ
		for(const [deg, pieces] of this.stand.stocks){ // this.stand.stocks гВТдљњзФ®
			for(const piece of pieces){
				newBoard.stand.add(piece.clone());
			}
		}

		// гБЭгБЃдїЦгБЃзКґжЕЛгВТгВ≥гГФгГЉ
		newBoard.turn = this.turn;
		newBoard.record = JSON.parse(JSON.stringify(this.record)); // и®ШйМ≤гВВгГЗгВ£гГЉгГЧгВ≥гГФгГЉ

		return newBoard;
	}
}
