import {canvasFont} from "./canvasFontLoader.js";
import {canvasImage} from "./canvasImageLoader.js";
import {panels} from "./data.js";
import {Piece} from "./piece.js";

/** гГЮгВєзЫЃгБЃзЃ°зРЖгВѓгГ©гВє */
export class Panel{
	#piece
	#isSelected;
	#targetRanges;

	/** йІТгВ™гГЦгВЄгВІгВѓгГИ
	 * @returns {Piece}
	 */
	get piece(){
		return this.#piece
	}
	set piece(piece){
		this.#piece = piece;
		if(!piece) return;
		piece.center = this.center;
		piece.middle = this.middle;
	}

	/**
	 * @param {any} ctx - CanvasжППзФїгВ≥гГ≥гГЖгВ≠гВєгГИ
	 * @param {string} char - гГЮгВєзЫЃгВТз§ЇгБЩжЦЗе≠Ч
	 * @param {number} center - жППеЖЩгБЩгВЛXеЇІж®Щ(дЄ≠ењГеОЯзВє)
	 * @param {number} middle - жППеЖЩгБЩгВЛYеЇІж®Щ(дЄ≠ењГеОЯзВє)
	 * @param {number} width - гГЮгВєзЫЃеєЕ
	 * @param {number} height - гГЮгВєзЫЃйЂШгБХ
	 * @param {number} pX - гГЬгГЉгГЙдЄКгБЃгГЮгВєзЫЃгБЃеИЧ
	 * @param {number} pY - гГЬгГЉгГЙдЄКгБЃгГЮгВєзЫЃгБЃи°М
	 * @param {number} borderWidth - жЮ†зЈЪгБЃе§™гБХ
	 */
	constructor(ctx, char, center, middle, width, height, pX, pY, borderWidth){
		Object.assign(this, panels[char]);
		this.ctx = ctx;
		this.center = center;
		this.middle = middle;
		this.width = width;
		this.height = height;
		this.left = center-width/2;
		this.top = middle-height/2;
		this.right = center+width/2;
		this.bottom = middle+height/2;
		this.pX = pX;
		this.pY = pY;
		this.borderWidth = borderWidth;
		this.selectColor ??= "#FF000066";
		this.targetColor ??= "#00FF0066";
		this.attr ??= [];
		this.piece = null;
		this.isSelected = false;
		this.clearTarget();
	}

	/** гГЮгВєзЫЃгБЃйБЄжКЮзКґжЕЛ
	 * @param {boolean} value
	 */
	set isSelected(value){
		this.#isSelected = this.hasAttr("keepOut")? false: value;
	}
	get isSelected(){
		return this.#isSelected;
	}

	/** гГЮгВєзЫЃгБЃзІїеЛХеПѓиГљеИ§еЃЪ
	 * @param {boolean} value
	 */
	get isTarget(){
		return 0 < this.#targetRanges.length;
	}

	/** гГЮгВєзЫЃгБЃзІїеЛХеЕИжГЕе†±гВТгВѓгГ™гВҐ */
	clearTarget(){
		this.#targetRanges = [];
	}

	/** гГЮгВєзЫЃгБЃзІїеЛХеЕИжГЕе†±гВТињљеК†
	 * @param {string} rangeName - зІїеЛХеЕИжГЕе†±
	 */
   addTarget(rangeName){
		this.#targetRanges.push(rangeName);
	}

	/** гГЮгВєзЫЃгБМзІїеЛХеЕИжГЕе†±гВТжМБгБ£гБ¶гБДгВЛгБЛеИ§еЃЪ
	 * @param {string} rangeName - зІїеЛХеЕИжГЕе†±
	 * @returns {boolean}
	 */
	hasTarget(rangeName){
		return this.#targetRanges.includes(rangeName);
	}

	/** е±ЮжАІгБЃе≠ШеЬ®гВТзҐЇи™Н
	 * @param {string} attrName - е±ЮжАІеРН
	 * @returns {boolean}
	 */
	hasAttr(attrName){
		return this.attr.includes(attrName);
	}
	/** еЇІж®ЩгБМгГЮгВєзЫЃгБЂеРЂгБЊгВМгВЛгБЛеИ§еЃЪ
	 * @param {number} x - XеЇІж®Щ
	 * @param {number} y - YеЇІж®Щ
	 * @returns {boolean}
	 */
	checkRangeMouse(x, y){
		return (
			this.left <= x && x < this.right &&
			this.top <= y && y < this.bottom
		);
	}

	/** гГЮгВєзЫЃ/гГЮгВєгВѓ/йІТгВТжППеЖЩ */
	draw(){
		if(!this.ctx) return;
		const {selectColor, targetColor} = this;

		if(this.imgSrc && canvasImage.imported)
			this.drawImage();
		else
			this.drawPanel();
		if(this.isSelected) this.drawMask(selectColor);
		if(this.isTarget) this.drawMask(targetColor);
		this.piece?.draw();
	}

	/** гГЮгВєзЫЃзФїеГПгВТжППеЖЩ */
	drawImage(){
		if(!this.ctx) return;
		const {ctx} = this;

		const src = this.imgSrc;
		const image = canvasImage.images[src];
		if(!image) return;

		ctx.save();
		ctx.translate(this.left, this.top);
		ctx.drawImage(image, 0, 0, this.width, this.height);
		ctx.restore();
	}

	/** гГЮгВєзЫЃгВТжППеЖЩ */
	drawPanel(){
		if(!this.ctx) return;
		const {ctx, left, top, center, middle, width, height, displayText, textRotate} = this;

		ctx.fillStyle = this.backgroundColor;
		ctx.strokeStyle = this.borderColor;
		ctx.lineWidth = this.borderWidth;

		ctx.save();
		ctx.translate(left, top);
		ctx.fillRect(0, 0, width, height);
		// дЇ§зВєгВТжППеЖЩ
		if(this.intersect){
			ctx.lineWidth = this.borderWidth;
			ctx.beginPath();
			ctx.moveTo(width/2, 0);
			ctx.lineTo(width/2, height);
			ctx.moveTo(0, height/2);
			ctx.lineTo(width, height/2);
			ctx.closePath();
			ctx.stroke();
		}
		// гГЮгВєзЫЃгВТжППеЖЩ
		else{
			ctx.strokeRect(0, 0, width, height);
		}

		// жЦЬзЈЪгВТжППеЖЩ
		ctx.lineWidth = this.borderWidth/2;
		ctx.beginPath();
		if(this.borderSlashLeft){
			ctx.moveTo(0, 0);
			ctx.lineTo(width, height);
		}
		if(this.borderSlashRight){
			ctx.moveTo(width, 0);
			ctx.lineTo(0, height);
		}
		ctx.closePath();
		ctx.stroke();
		ctx.restore();

		// жЦЗе≠ЧгВТжППеЖЩ
		if(displayText){
			ctx.save();
			ctx.translate(center, middle);
			ctx.fillStyle = this.borderColor;

			const rad = textRotate? textRotate*Math.PI/180: 0;
			ctx.rotate(rad);

			const fontSize = Math.min(this.width, this.height)*0.6;
			ctx.font = `${fontSize}px ${canvasFont.names}`;

			const width = ctx.measureText(displayText).width;
			const height = fontSize/2*0.8;
			ctx.fillText(displayText, -width/2, height);
			ctx.restore();
		}
	}

	/** гГЮгВєзЫЃгБЂгГЮгВєгВѓгВТжППеЖЩ
	 * @param {string} color - гВЂгГ©гГЉгВ®гГХгВІгВѓгГИгБЃиЙ≤
	 */
	drawMask(color){
		if(!this.ctx) return;
		const {ctx} = this;

		ctx.fillStyle = color;

		// гГЮгВєзЫЃгВТжППеЖЩ
		ctx.fillRect(this.left, this.top, this.width, this.height);
	}

	/** гГЮгВєзЫЃгВТгГЖгВ≠гВєгГИељҐеЉПгБІеПЦеЊЧ
	 * @param {boolean} isCompact - гВ≥гГ≥гГСгВѓгГИи°®з§Ї
	 */
	toString(isCompact=false){
		return !isCompact?
			this.text:
			`пљЬ${this.text.slice(-1).replace(/гАА/g, "гГї")}`;
	}
}
