import {Panel} from "./panel.js";
import {Piece} from "./piece.js";

const degs = Object.keys(Piece.degChars);
const getInit = ()=>({
	panel: null,
	piece: null
});

/** гВҐгГ≥гГСгГГгВµгГ≥жГЕе†±гБЃзЃ°зРЖ */
export class EnPassant{
	constructor(){
		/** @type {Object<string, {panel: Panel, piece: Piece}>} */
		this.degs = {};
		degs.forEach(deg=>this.degs[deg] = getInit());
	}

	/** гВҐгГ≥гГСгГГгВµгГ≥жГЕе†±гВТгВѓгГ™гВҐ
	 * @param {number} deg - гВҐгГ≥гГСгГГгВµгГ≥гБХгВМгБЖгВЛйЩ£еЦґгБЃиІТеЇ¶
	 */
	clear(deg){
		this.degs[deg] = getInit();
	}

	/** гВҐгГ≥гГСгГГгВµгГ≥еѓЊи±°гБ®жИРгВКгБЖгВЛгГЮгВєжГЕе†±гВТи®ШйМ≤
	 * @param {Panel} panel - гВҐгГ≥гГСгГГгВµгГ≥еѓЊи±°гБ®жИРгВКгБЖгВЛгГЮгВєзЫЃ
	 * @param {Piece} piece - гВҐгГ≥гГСгГГгВµгГ≥еѓЊи±°гБ®жИРгВКгБЖгВЛйІТ
	 */
	setTarget(panel, piece){
		if(panel.hasTarget("start") && piece.hasAttr("enPassant"))
			this.degs[piece.deg].panel = panel;
	}

	/** гВҐгГ≥гГСгГГгВµгГ≥еѓЊи±°гБ®жИРгВКгБЖгВЛйІТжГЕе†±гВТи®ШйМ≤
	 * @param {Panel} toPanel - гВҐгГ≥гГСгГГгВµгГ≥еѓЊи±°гБЛзҐЇи™НгБЩгВЛгГЮгВєзЫЃ
	 */
	setMoved(toPanel){
		const {piece} = toPanel;
		const ep = this.degs[piece.deg];
		if(piece && toPanel === ep.panel) ep.piece = piece;
		else this.clear(piece.deg);
	}

	/** гВҐгГ≥гГСгГГгВµгГ≥еѓЊи±°гБЃгГЮгВєгБЛзҐЇи™НгБЩгВЛ
	 * @param {Panel} panel - гВҐгГ≥гГСгГГгВµгГ≥еѓЊи±°гБ®жИРгВКгБЖгВЛгГЮгВєзЫЃ
	 * @param {Piece} piece - гВҐгГ≥гГСгГГгВµгГ≥еѓЊи±°гБ®жИРгВКгБЖгВЛйІТ
	 * @returns {boolean}
	 */
	isTarget(panel, piece){
		if(!panel || !panel.piece) return true;
		if(!panel.piece.hasAttr("enPassant")) return false;
		return panel.piece === this.degs[panel.piece.deg].piece;
	}
}
