import {Stand} from "./stand.js";
import {Piece} from "./piece.js";

/** BODељҐеЉПгБЃгБЯгВБгБЃйЦҐжХ∞еЃЪзЊ©гБ™гБ© */
export class Bod{
	/** иІТеЇ¶гБЛгВЙйІТгБЃжЦЗе≠Чи°®з§Ї
	 * @type {Map<number, string>}
	 */
	static #deg2PieceChars = new Map([
		[0, " "],
		[90, ">"],
		[180, "v"],
		[270, "<"]
	]);

	/** иІТеЇ¶гБЛгВЙйІТгБЃж≠£и¶Пи°®зПЊи°®з§Ї
	 * @type {Map<number, string>}
	 */
	static #deg2PieceRegexes = new Map(
		[...Bod.#deg2PieceChars]
		.map(([a, b])=>[a, new RegExp(b, "g")])
	);

	/** йІТгБЃжЦЗе≠ЧгБЛгВЙиІТеЇ¶и°®з§Ї
	 * @type {Map<string, number>}
	 */
	static #pieceChar2Degs = new Map(
		[...Bod.#deg2PieceChars]
		.map(([a, b])=>[b, a])
	);

	/** иІТеЇ¶гБЛгВЙжМБйІТгБЃи°®й°Ми°®з§Ї
	 * @type {Map<number, string>}
	 */
	static #deg2StandTitles = new Map([
		[0, "еЕИжЙЛгБЃжМБйІТ"],
		[90, "жђ°жЙЛгБЃжМБйІТ"],
		[180, "еЊМжЙЛгБЃжМБйІТ"],
		[270, "еЫЫжЙЛгБЃжМБйІТ"]
	]);

	/** жМБйІТгБЃи°®й°МгБЛгВЙиІТеЇ¶и°®з§Ї
	 * @type {Map<string, number>}
	 */
	static #standTitle2Degs = new Map(
		[...Bod.#deg2StandTitles]
		.map(([a, b])=>[b, a])
	);

	static #kanI = ["","дЄА","дЇМ","дЄЙ","еЫЫ","дЇФ","еЕ≠","дЄГ","еЕЂ","дєЭ"];
	static #kanX = ["","еНБ","дЇМеНБ","дЄЙеНБ","еЫЫеНБ","дЇФеНБ","еЕ≠еНБ","дЄГеНБ","еЕЂеНБ","дєЭеНБ"];

	/** и°М/жМБйІТзФ®гБЃжХ∞е≠Чи°®з§Ї(жЉҐжХ∞е≠Ч)
	 * @param {number} num - жХ∞е≠Ч
	 * @param {boolean} viewOne - дЄАгВТи°®з§Ї
	 * @returns {string}
	 */
	static #num2Kan(num, viewOne=true){
		if(!viewOne && num<=1) return "";
		const i = num%10;
		const x = 0|num/10;
		return Bod.#kanX[x]+Bod.#kanI[i];
	}

	/** и°М/жМБйІТзФ®гБЃжХ∞е≠Чи°®з§Ї(жЉҐжХ∞е≠Ч)
	 * @param {string} kan - жЉҐжХ∞е≠Ч
	 * @param {boolean} emptyOne - з©ЇжЦЗе≠ЧгВТ1гБ®гБЩгВЛ
	 * @returns {string}
	 */
	static #kan2Num(kan, emptyOne=true){
		if(emptyOne && kan === "") return 1;
		if(!isNaN(kan)) return 0|kan;
		let x = Bod.#kanX.findIndex(key=>
			key !== "" && (new RegExp("^"+key)).test(kan)
		);
		if(x < 0) x = 0;
		let i = Bod.#kanI.findIndex(key=>
			key !== "" && (new RegExp(key+"$")).test(kan)
		);
		if(i < 0) i = 0;
		return x*10+i;
	}

	/** еИЧзФ®гБЃжХ∞е≠Чи°®з§Ї(еЕ®иІТ/2ж°Б)
	 * @param {number} num - жХ∞е≠Ч
	 * @returns {string}
	 */
	static #num2Zen(num){
		if(10<=num) return num;
		const zen = "пЉРпЉСпЉТпЉУпЉФпЉХпЉЦпЉЧпЉШпЉЩ";
		const i = num%10;
		return zen[i];
	}

	/** гГЮгВєзЫЃгБЃи°®з§Ї
	 * @type {string}
	 */
	static #panelText = " гГї";

	/** йІТгБЃBODи°®и®Ш
	 * @param {Piece} piece - йІТ
	 * @returns {string}
	 */
	static #getTextPiece(piece){
		if(!piece) return Bod.#panelText;
		return Bod.#deg2PieceChars.get(piece.deg)+piece.char;
	}

	/** йІТеП∞гБЃBODи°®и®Ш
	 * @param {Stand} stand - йІТеП∞
	 * @param {number} deg - иІТеЇ¶
	 * @returns {string}
	 */
	static #getTextStand(stand, deg=0){
		// йІТжХ∞гВЂгВ¶гГ≥гГИ
		const counter = new Map();
		stand.stocks.get(deg).forEach(({char})=>{
			if(!counter.has(char)) counter.set(char, 0);
			counter.set(char, counter.get(char)+1);
		});
		return Bod.#deg2StandTitles.get(deg)+"пЉЪ"+
			[...counter].map(([char, cnt])=>
				char+Bod.#num2Kan(cnt, false)
			).join(" ");
	}

	/** BODељҐеЉПгБЃгГЖгВ≠гВєгГИгВТгГЬгГЉгГЙгБІжЙ±гБИгВЛгВИгБЖе§ЙжПЫ
	 * @param {string} text - BODељҐеЉПгБЃгГЖгВ≠гВєгГИ
	 * @returns {string}
	 */
	static convTextPieces(text){
		const boardLines = [];
		const standLines = [];
		text.split(/\r|\n|\r\n/).forEach(line=>{
			if([...Bod.#standTitle2Degs.keys()].some(title=>
				new RegExp(`^${title}`).test(line))
			) standLines.push(line);
			else boardLines.push(line.slice(1))
		});

		let boardStr = boardLines.slice(2, -1).join("\n");
		Bod.#deg2PieceRegexes.forEach((bodChar, deg)=>{
			boardStr = boardStr.replace(bodChar, Piece.degChars[deg]);
		})

		const standStr = standLines.flatMap(line=>{
			const [title, paramStr] = line.split(/пЉЪ/);
			if(paramStr === "") return "";
			const deg = Bod.#standTitle2Degs.get(title);
			const degChar = Piece.degChars[deg];
			const params = paramStr
				.split(/\s/)
				.map(param=>{
					const pieceChar = param[0];
					const kan = param.slice(1);
					return (degChar+pieceChar).repeat(Bod.#kan2Num(kan));
				});
			return params;
		}).join("");

		return `${boardStr}\n${standStr}`;
	}

	/** BODељҐеЉПгГЖгВ≠гВєгГИгВТеПЦеЊЧ
	 * @returns {string}
	 */
	static getTextPieces(board){
		const {field, xLen, playerLen, stand} = board;

		let header =
			` ${[...Array(xLen).keys()].map(i=>` ${Bod.#num2Zen(xLen-i)}`).join("")}\n`+
			`+${Array(xLen).fill("---").join("")}+\n`;
		let footer = `\n+${Array(xLen).fill("---").join("")}+`;
		let panelOuter = "|";
		let panelSep = "";
		let rowSep = "\n";
		let standHeader = `${Bod.#getTextStand(stand, 180)}\n`;
		let standFooter = `${Bod.#getTextStand(stand, 0)}`;
		if(playerLen !== 2){
			standHeader = `${Bod.#getTextStand(stand, 270)}\n`+standHeader;
			standFooter = `${Bod.#getTextStand(stand, 90)}\n`+standFooter;
		}

		return (
			standHeader+
			header+
			field.map((row, i)=>
				panelOuter+
				row.map(panel=>
					Bod.#getTextPiece(panel.piece)
				).join(panelSep)+
				panelOuter+
				Bod.#num2Kan(i+1)
			).join(rowSep)+
			footer+"\n"+
			standFooter
		);
	}
}
