import {panels, pieces} from "./data.js";

/** зФїеГПи™≠гБњиЊЉгБњеЗ¶зРЖ
 * @param {string} src - зФїеГПгГСгВє
 * @returns Promise<Image>
 */
function loadImage(src){
	return new Promise(resolve=>{
		const image = new Image();
		image.src = src;
		image.onload = ()=>resolve(image);
	});
}

/** и™≠гБњиЊЉгВАзФїеГПгГСгВєгБЃдЄАи¶І
 * @type {string[]}
 */
function getImgSrcs(){
	return [...new Set(
		Object.values(panels).flatMap(({imgSrc})=>imgSrc??[])
		.concat(Object.values(pieces).flatMap(({imgSrc})=>
			imgSrc != null? Object.values(imgSrc): []).flat())
	)];
};

/** CanvasзФ®зФїеГПгБЃзЃ°зРЖ */
export const canvasImage = {
	/** и™≠гБњиЊЉгБњжЄИгБњгБІгБВгВЛгБЛ? */
	imported: false,

	/** и™≠гБњиЊЉгВУгБ†зФїеГПгГЗгГЉгВњ
	 * @type {Object<string, Image>}
	 */
	images: {},

	/** зФїеГПгБЃи™≠гБњиЊЉгБњ
	 * @returns {Promise<void>}
	 */
	async importAsync(){
		if(this.imported) return;
		return Promise.all(
			getImgSrcs().map(async src=>{
				this.images[src] = await loadImage(src);
			})
		).then(_=>this.imported = true)
	}
};

