/** @typedef {import('./data').PlayerInfo} PlayerInfo */
import {Board} from "./board.js";
import {checkTarget, isCheckmate, hasLegalMoves} from "./checkTarget.js";

/** еЯЇеЇХCPUгВ®гГ≥гВЄгГ≥(жЙЛеЛХжУНдљЬзФ®) */
export class CpuEngineBase{
	/**
	 * @param {Board} board - еѓЊи±°гБЃгГЬгГЉгГЙ
	 * @param {PlayerInfo} player - гГЧгГђгВ§гГ§гГЉжГЕе†±
	 */
	constructor(board, player){
		this.board = board;
		this.player = player;
	}
	/** жЙЛзХ™жУНдљЬ */
	playTurn(){
		// жУНдљЬгБ™гБЧ
	}

	/**
	 * зЫ§йЭҐгВТи©ХдЊ°гБЧгБЊгБЩгАВ
	 * @returns {number} зЫ§йЭҐгБЃи©ХдЊ°еА§
	 */
	evaluate(){
		const {board, player} = this;
		const KING_VALUE = 10000; // зОЛгБЃдЊ°еА§
		let my_score = 0;
		let opponent_score = 0;

		// зЫ§дЄКгБЃйІТгВТи©ХдЊ°
		board.field.flat().forEach(panel=>{
			if(panel.piece){
				const is_king = panel.piece.cost <= 0;
				const value = is_king ? KING_VALUE : panel.piece.cost;
				if(panel.piece.deg === player.deg){
					my_score += value;
				}
				else{
					opponent_score += value;
				}
			}
		});


		// жМБгБ°йІТгВТи©ХдЊ°
		board.stand.stocks.forEach((pieces, deg)=>{
			const hand_value = pieces.reduce((acc, piece)=>acc + piece.cost, 0); // зОЛгБѓжМБгБ°йІТгБЂгБ™гВЙгБ™гБД
			if(deg === player.deg){
				my_score += hand_value;
			}
			else{
				opponent_score += hand_value;
			}
		});
		return my_score - opponent_score;
	}
}

/** CPUгВ®гГ≥гВЄгГ≥ */
export const CpuEngines = {};

/** гГ©гГ≥гГАгГ†гБІжЙЛгВТжЙУгБ§гВ®гГ≥гВЄгГ≥ */
CpuEngines.random = class Random extends CpuEngineBase{
	constructor(board, player){
		super(board, player);
	}

	playTurn(){
		const {board, player} = this;

		// 1. зПЊеЬ®гБЃгГЧгГђгВ§гГ§гГЉгБМеЛХгБЛгБЫгВЛйІТгВТгБЩгБєгБ¶еПЦеЊЧ
		const movablePieces = [];
		board.field.flat().forEach(panel=>{
			if(panel.piece && panel.piece.deg === player.deg){
				const fromPanel = panel;
				const toPanels = checkTarget(board, fromPanel.piece, fromPanel.pX, fromPanel.pY);
				if(toPanels.length > 0){
					movablePieces.push({from: fromPanel, tos: toPanels});
				}
			}
		});


		// 2. гБЩгБєгБ¶гБЃеПѓиГљгБ™жЙЛгБЃгГ™гВєгГИгВТдљЬжИР
		const allPossibleMoves = [];
		movablePieces.forEach(({from, tos})=>{
			tos.forEach(to=>{
				allPossibleMoves.push({from, to});
			});
		});

		// 3. жМЗгБЧжЙЛгБМе≠ШеЬ®гБЩгВЛе†іеРИгАБгГ©гГ≥гГАгГ†гБЂ1гБ§йБЄгВУгБІжМЗгБЩ
		if(allPossibleMoves.length > 0){
			const randomMove = allPossibleMoves[Math.floor(Math.random() * allPossibleMoves.length)];
			board.movePiece(randomMove.from, randomMove.to, true);
			console.log(`CPU(Random): (${randomMove.from.pX}, ${randomMove.from.pY}) гБЛгВЙ (${randomMove.to.pX}, ${randomMove.to.pY}) гБЄзІїеЛХ`);
		}
		else{
			console.log("CPU(Random): жМЗгБЧжЙЛгБМгБВгВКгБЊгБЫгВУгАВ");
			// гВ≤гГЉгГ†зµВдЇЖгВДгГСгВєеЗ¶зРЖ
		}
	}
}

/** и≤™жђ≤ж≥ХгВ®гГ≥гВЄгГ≥ (1жЙЛи™≠гБњ) */
CpuEngines.greedy = class Greedy extends CpuEngineBase{
	constructor(board, player){
		super(board, player);
	}

	/**
	 * жЙЛзХ™гВТеЗ¶зРЖгБЧгБЊгБЩгАВ
	 */
	playTurn(){
		const {board, player} = this;

		const movablePieces = [];
		board.field.flat().forEach(panel=>{
			if(panel.piece && panel.piece.deg === player.deg){
				const fromPanel = panel;
				const toPanels = checkTarget(board, fromPanel.piece, fromPanel.pX, fromPanel.pY);
				if(toPanels.length > 0){
					movablePieces.push({from: fromPanel, tos: toPanels});
				}
			}
		});

		const allPossibleMoves = [];
		movablePieces.forEach(({from, tos})=>{
			tos.forEach(to=>{
				allPossibleMoves.push({from, to});
			});
		});

		if(allPossibleMoves.length === 0){
			console.log("CPU(Greedy): жМЗгБЧжЙЛгБМгБВгВКгБЊгБЫгВУгАВ");
			return;
		}

		let bestMove = null;
		let bestScore = -Infinity;

		allPossibleMoves.forEach(move=>{
			const boardClone = board.clone();
			boardClone.isHeadless = true;
			// гВѓгГ≠гГЉгГ≥зЫ§дЄКгБЃгГСгГНгГЂгВТеПЦеЊЧ
			const fromPanelClone = boardClone.field[move.from.pY][move.from.pX];
			const toPanelClone = boardClone.field[move.to.pY][move.to.pX];
			boardClone.movePiece(fromPanelClone, toPanelClone);
			const score = this.evaluate();
			if(score > bestScore){
				bestScore = score;
				bestMove = move;
			}
		});

		if(bestMove){
			board.movePiece(bestMove.from, bestMove.to,true);
			console.log(`CPU(Greedy): (${bestMove.from.pX}, ${bestMove.from.pY}) гБЛгВЙ (${bestMove.to.pX}, ${bestMove.to.pY}) гБЄзІїеЛХ (и©ХдЊ°еА§: ${bestScore})`);
		}
		else{
			// жМЗгБЧжЙЛгБМгБВгВЛе†іеРИгБѓгБУгБУгБЂгБѓжЭ•гБ™гБДгБѓгБЪ
			console.log("CPU(Greedy): жЬАеЦДжЙЛгБМи¶ЛгБ§гБЛгВКгБЊгБЫгВУгБІгБЧгБЯгАВ");
		}
	}
}

/** гГЯгГЛгГЮгГГгВѓгВєгВ®гГ≥гВЄгГ≥ (гВҐгГЂгГХгВ°гГЩгГЉгВњжЮЭеИИгВКдїШгБН) */
CpuEngines.minimax = class Minimax extends CpuEngineBase {
	constructor(board, player){
		super(board, player);
		this.searchDepth = 3; // жОҐзіҐгБЃжЈ±гБХ
	}

	/**
	 * гГЯгГЛгГЮгГГгВѓгВєж≥ХпЉИгВҐгГЂгГХгВ°гГЩгГЉгВњжЮЭеИИгВКдїШгБНпЉЙгВТеЃЯи°МгБЧгБЊгБЩгАВ
	 * @param {Board} board - зПЊеЬ®гБЃзЫ§йЭҐ
	 * @param {number} depth - жЃЛгВКгБЃжОҐзіҐжЈ±гБХ
	 * @param {number} alpha - гВҐгГЂгГХгВ°еА§
	 * @param {number} beta - гГЩгГЉгВњеА§
	 * @param {boolean} isMaximizingPlayer - зПЊеЬ®гБЃгГЧгГђгВ§гГ§гГЉгБМжЬАе§ІеМЦгГЧгГђгВ§гГ§гГЉгБЛгБ©гБЖгБЛ
	 * @returns {number} и©ХдЊ°еА§
	 */
	minimax(board, depth, alpha, beta, isMaximizingPlayer){
		const {player} = this;

		// жОҐзіҐгБЃзµВдЇЖжЭ°дїґ
		if(depth === 0) return this.evaluate();

		// и©∞гБњ/гВєгГЖгГЉгГЂгГ°гВ§гГИгБЃеИ§еЃЪ
		if(isCheckmate(board, player.deg))
			return isMaximizingPlayer ? -Infinity : Infinity; // и©∞гБњгБѓжЬАе§ІеМЦгГЧгГђгВ§гГ§гГЉгБЂгБ®гБ£гБ¶йЭЮеЄЄгБЂжВ™гБДзКґжЕЛ
		if(!hasLegalMoves(board, player.deg))
			return 0; // гВєгГЖгГЉгГЂгГ°гВ§гГИпЉИеРИж≥ХжЙЛгБМгБ™гБДгБМзОЛжЙЛгБІгБѓгБ™гБДпЉЙ

		// еРИж≥ХжЙЛгБЃзФЯжИР
		const movablePieces = [];
		board.field.flat().forEach(panel=>{
			if(panel.piece && panel.piece.deg === player.deg){
				const fromPanel = panel;
				const toPanels = checkTarget(board, fromPanel.piece, fromPanel.pX, fromPanel.pY);
				if(toPanels.length > 0){
					movablePieces.push({from: fromPanel, tos: toPanels});
				}
			}
		});

		const allPossibleMoves = [];
		movablePieces.forEach(({from, tos})=>{
			tos.forEach(to=>{
				allPossibleMoves.push({from, to});
			});
		});

		if(isMaximizingPlayer){
			let maxEval = -Infinity;
			for(const move of allPossibleMoves){
				const boardClone = board.clone();
				boardClone.isHeadless = true;
				const fromPanelClone = boardClone.field[move.from.pY][move.from.pX];
				const toPanelClone = boardClone.field[move.to.pY][move.to.pX];
				boardClone.movePiece(fromPanelClone, toPanelClone);

				const minimaxEval = this.minimax(boardClone, depth - 1, alpha, beta, false);
				maxEval = Math.max(maxEval, minimaxEval);
				alpha = Math.max(alpha, minimaxEval);
				if(beta <= alpha) break; // гВҐгГЂгГХгВ°гГЩгГЉгВњжЮЭеИИгВК
			}
			return maxEval;
		}
		else{ // жЬАе∞ПеМЦгГЧгГђгВ§гГ§гГЉ
			let minEval = Infinity;
			for(const move of allPossibleMoves){
				const boardClone = board.clone();
				boardClone.isHeadless = true;
				const fromPanelClone = boardClone.field[move.from.pY][move.from.pX];
				const toPanelClone = boardClone.field[move.to.pY][move.to.pX];
				boardClone.movePiece(fromPanelClone, toPanelClone);

				const minimaxEval = this.minimax(boardClone, depth - 1, alpha, beta, true);
				minEval = Math.min(minEval, minimaxEval);
				beta = Math.min(beta, minimaxEval);
				if(beta <= alpha) break; // гВҐгГЂгГХгВ°гГЩгГЉгВњжЮЭеИИгВК
			}
			return minEval;
		}
	}

	/**
	 * жЙЛзХ™гВТеЗ¶зРЖгБЧгБЊгБЩгАВ
	 */
	playTurn(){
		const {board, player} = this;

		let bestMove = null;
		let bestScore = -Infinity;

		// еРИж≥ХжЙЛгБЃзФЯжИР
		const movablePieces = [];
		board.field.flat().forEach(panel => {
			if(panel.piece && panel.piece.deg === player.deg){
				const fromPanel = panel;
				const toPanels = checkTarget(board, fromPanel.piece, fromPanel.pX, fromPanel.pY);
				if(toPanels.length > 0){
					movablePieces.push({from: fromPanel, tos: toPanels});
				}
			}
		});

		const allPossibleMoves = [];
		movablePieces.forEach(({from, tos})=>{
			tos.forEach(to=>{
				allPossibleMoves.push({from, to});
			});
		});

		if(allPossibleMoves.length === 0){
			console.log("CPU(Minimax): жМЗгБЧжЙЛгБМгБВгВКгБЊгБЫгВУгАВ");
			return;
		}

		// еРДеРИж≥ХжЙЛгВТи©ХдЊ°
		for(const move of allPossibleMoves){
			const boardClone = board.clone();
			boardClone.isHeadless = true;
			const fromPanelClone = boardClone.field[move.from.pY][move.from.pX];
			const toPanelClone = boardClone.field[move.to.pY][move.to.pX];
			boardClone.movePiece(fromPanelClone, toPanelClone);

			// гГЯгГЛгГЮгГГгВѓгВєжОҐзіҐгВТйЦЛеІЛ (зЫЄжЙЛгБЃзХ™гБ™гБЃгБІisMaximizingPlayerгБѓfalse)
			const score = this.minimax(boardClone, this.searchDepth - 1, -Infinity, Infinity, false);

			if(score > bestScore){
				bestScore = score;
				bestMove = move;
			} else if(score === bestScore){
				// и©ХдЊ°еА§гБМеРМгБШе†іеРИгАБгГ©гГ≥гГАгГ†гБЂйБЄжКЮгБЧгБ¶зє∞гВКињФгБЧгВТйБњгБСгВЛ
				if(Math.random() < 0.5){ // 50%гБЃзҐЇзОЗгБІжЦ∞гБЧгБДжЙЛгВТйБЄгБґ
					bestMove = move;
				}
			}
		}

		if(bestMove){
			board.movePiece(bestMove.from, bestMove.to, true);
			console.log(`CPU(Minimax): (${bestMove.from.pX}, ${bestMove.from.pY}) гБЛгВЙ (${bestMove.to.pX}, ${bestMove.to.pY}) гБЄзІїеЛХ (и©ХдЊ°еА§: ${bestScore})`);
		}
		else{
			console.log("CPU(Minimax): жЬАеЦДжЙЛгБМи¶ЛгБ§гБЛгВКгБЊгБЫгВУгБІгБЧгБЯгАВ");
		}
	}
}

/** CPUгВ®гГ≥гВЄгГ≥гБЃзЃ°зРЖгВѓгГ©гВє */
export class CpuEngine extends CpuEngineBase {
	/**
	 * @param {Board} board - еѓЊи±°гБЃгГЬгГЉгГЙ
	 * @param {PlayerInfo} player - гГЧгГђгВ§гГ§гГЉжГЕе†±
	 */
	constructor(board, player){
		super(board, player);
		const engineName = player.cpuEngine?.toLowerCase();
		this.engine = engineName==null?
			new CpuEngineBase(board, player):
			new CpuEngines[engineName](board, player);
		if(!this.engine) throw new Error(`Engine "${engineName}" not found.`);
	}
	/** жЙЛзХ™жУНдљЬ */
	playTurn(){
		this.engine.playTurn();
	}
}
