import {Piece} from "./piece.js";

/** зЫ§гБЃзЃ°зРЖгВѓгГ©гВє */
export class Stand{
	/** йІТеП∞гБЄгБЃиІТеЇ¶гБФгБ®гБЃи°®з§Їй†Ж
	 * @type {number[]}
	 */
	static #degOrder = [180, 90, 270, 0];

	/**
	 * @param {Board} гГЬгГЉгГЙ
	 */
	constructor(board){
		this.board = board;
		const {top, right, bottom, width, height, panelWidth, panelHeight, xLen, yLen} = board;

		this.clear();
		this.left = right*1.02;
		this.top = top;
		this.width = width/2;
		this.height = height;
		this.right = this.left+this.width;
		this.bottom = bottom;
		this.pitchWidth = panelWidth/2;
		this.pitchHeight = panelHeight;
		this.xLen = xLen;
		this.yLen = yLen;
	}

	/** йІТеП∞гВТеИЭжЬЯеМЦгБЂгБЩгВЛ */
	clear(){
		this.stocks = new Map(Stand.#degOrder.map(i=>[i,[]]));
	}

	/** жМБгБ°йІТгБЛгВЙгГЬгГЉгГЙдЄКгБЂйЕНзљЃгБЩгВЛ
	 * @param {Panal} toPanell - йЕНзљЃеЕИгБЃгГСгГНгГЂ
	 * @param {Object} option - гВ™гГЧгВЈгГІгГ≥
	 * @param {number} option.deg - иІТеЇ¶
	 * @param {number} option.i - йЕНзљЃгБЩгВЛжМБгБ°йІТгБЃгВ§гГ≥гГЗгГГгВѓгВє
	 */
	releasePiece(toPanel, option={}){
		const {board} = this;
		if(board.moveMode === "viewOnly" || toPanel.hasAttr("keepOut")) return;

		const {deg, i} = option
		const stock = this.stocks.get(deg);
		toPanel.piece = stock[i];
		stock[i].center = toPanel.center;
		stock[i].middle = toPanel.middle;
		stock.splice(i,1);
		board.addRecord({toPanel, end: "жЙУ"});
	}

	/** йІТеП∞гБЂињљеК†гБЩгВЛ
	 * @param {Piece} piece - ињљеК†гБЩгВЛйІТ
	 */
	add(piece){
		const stock = this.stocks.get(piece.deg);
		piece.turnFront();
		stock.push(piece);
		stock.sort((a,b)=>Math.sign(a.id-b.id));
	}

	/** йІТгВТжМБгБ°йІТгБЂгБЩгВЛ
	 * @param {Piece|null} winnerPiece - зІїеЛХгБЩгВЛйІТ
	 * @param {Piece} loserPiece - жНХзЄЫгБХгВМгВЛйІТ
	 * @param {boolean} forceCapture - е±ЮжАІгВТзД°и¶ЦгБЧгБ¶жНХзЄЫгБЩгВЛ
	 * @param {boolean} forceCantCapture - е±ЮжАІгВТзД°и¶ЦгБЧгБ¶жНХзЄЫгБЧгБ™гБД
	 */
	capturePiece(winnerPiece, loserPiece, forceCapture=false, forceCantCapture=false){
		if(forceCantCapture
			|| !loserPiece
			|| !(forceCapture || winnerPiece.hasAttr("capture"))
			|| loserPiece.hasAttr("king")
			|| loserPiece.hasAttr("cantCapture")
		) return;

		loserPiece.deg = winnerPiece.deg;
		loserPiece.isMoved = true;
		this.add(loserPiece);
	}

	/** жМБгБ°йІТгБЃжЙАжЬЙж®©гВТеЫЮиїҐ
	 * @param {number} deg - еЫЮиїҐиІТ (90гБЃеАНжХ∞)
	 */
	rotate(deg){
		[...this.stocks].forEach(([standDeg, stock])=>{
			const pieceDeg = this.board.degNormal(standDeg+deg);
			stock.forEach(piece=>piece.deg = pieceDeg);
			this.stocks.set(pieceDeg, stock);
		})
	}

	/** зЫ§гВТжППеЖЩ */
	draw(){
		const {board, left, top, width, height, pitchWidth, pitchHeight} = this;
		const {ctx, xLen, yLen} = board;

		// е§ЦжЮ†гВТжППеЖЩ
		ctx.fillStyle = board.backgroundColor;
		ctx.strokeStyle = board.borderColor;
		ctx.lineWidth = board.borderWidth;

		ctx.save();
		ctx.translate(left, top);
		ctx.fillRect(0, 0, width, height);
		ctx.strokeRect(0, 0, width, height);
		ctx.restore();

		[...this.stocks.values()].forEach((stock, player)=>{
			let i = 0;
			// жЇҐгВМгБЯе†іеРИгБѓеЊМжЦєеД™еЕИгБІи°®з§Ї
			stock = stock.slice(-yLen/4*xLen);
			for(let pY=0|yLen/4*player;pY<yLen/4*(player+1);pY++){
				for(let pX=0;pX<xLen;pX++){
					const center = left+pitchWidth*(pX+1);
					const middle = top+pitchHeight*(pY+1);
					const piece = stock[i++];
					if(piece == null) break;
					piece.center = center;
					piece.middle = middle;
					piece.draw();
				}
			}
		});
	}

	/** йІТеП∞гВТгГЖгВ≠гВєгГИељҐеЉПгБІеПЦеЊЧ
	 * @param {boolean} isCompact - гВ≥гГ≥гГСгВѓгГИи°®з§Ї
	 * @param {boolean} isAlias - гВ®гВ§гГ™гВҐгВєи°®з§Ї
	 */
	toString(isCompact=false, isAlias=false){
		const {xLen} = this.board;
		const stock = [...this.stocks.values()].flat().filter(v=>v);

		let head = 0 < stock.length? "\n"+"вАХ".repeat(xLen*2)+"\n": "";
		let text = stock.map(p=>p.toString(isAlias)).join("");
		if(!isCompact){
			head = "";
			for(const char of Object.values(Piece.degChars)){
				text = text.replace(char, "\n"+`${char}жМБйІТпЉЪ${char}`);
			}
		}
		return head+text;
	}
}
